def escape_html(text):
    """Escape HTML special characters."""
    return html_lib.escape(text)


def parse_formatting(text):
    """Convert **text** to bold and _text_ to italic."""
    text = re.sub(r'\*\*(.+?)\*\*', r'<strong>\1</strong>', text)
    text = re.sub(r'_(.+?)_', r'<em>\1</em>', text)
    return text


def _split_table_row(line):
    """Split a markdown table row on | while respecting escaped pipes (\|).

    Handles escaped pipes (\|) and escaped backslashes (\\\\) correctly.
    Returns a list of cell strings with escaped sequences unescaped.
    """
    cells = []
    current_cell = []
    i = 0

    while i < len(line):
        if line[i] == '\\' and i + 1 < len(line):
            # Check what follows the backslash
            if line[i + 1] == '|':
                # Escaped pipe: add literal pipe to current cell
                current_cell.append('|')
                i += 2
            elif line[i + 1] == '\\':
                # Escaped backslash: add literal backslash
                current_cell.append('\\')
                i += 2
            else:
                # Backslash not escaping pipe or backslash, keep as-is
                current_cell.append(line[i])
                i += 1
        elif line[i] == '|':
            # Unescaped pipe: delimiter, start new cell
            cells.append(''.join(current_cell))
            current_cell = []
            i += 1
        else:
            # Regular character
            current_cell.append(line[i])
            i += 1

    # Add the final cell (after last |)
    cells.append(''.join(current_cell))

    return cells


def parse_markdown_table(table_text):
    """Parse markdown table to HTML table."""
    lines = [line.strip() for line in table_text.strip().split('\n') if line.strip()]

    if len(lines) < 2:
        return f"<p>{escape_html(table_text)}</p>"

    # Find header row (first row with |)
    header_row = None
    data_rows = []

    for i, line in enumerate(lines):
        if '|' in line:
            parts = [cell.strip() for cell in _split_table_row(line)]
            # Remove only ONE empty string from start and end (markdown tables have | at boundaries)
            # but preserve intentional empty cells in the middle or at edges
            if parts and not parts[0]:
                parts.pop(0)
            if parts and not parts[-1]:
                parts.pop()

            if header_row is None:
                header_row = parts
            elif not all(c in '-:|' for c in line.replace(' ', '')):
                # Skip separator lines like |---|---|
                row = parts + [''] * (len(header_row) - len(parts))
                data_rows.append(row)

    if not header_row:
        return f"<p>{escape_html(table_text)}</p>"

    # Build table HTML
    html = '<table>\n  <thead>\n    <tr>'
    for header in header_row:
        html += f'<th>{parse_formatting(escape_html(header))}</th>'
    html += '</tr>\n  </thead>\n  <tbody>\n'

    for row in data_rows:
        html += '    <tr>'
        for cell in row:
            html += f'<td>{parse_formatting(escape_html(cell))}</td>'
        html += '</tr>\n'

    html += '  </tbody>\n</table>'
    wrapped_html = f'''
<div class="content-block">
  <div class="content-header"><button class="copy-btn" onclick="copyTable(this)">Copy table</button></div>
  <div class="table-wrapper">{html}</div>
</div>'''
    return wrapped_html


BULLET_MARKERS = ('- ', '• ', '* ', '▪ ')


def _get_bullet_indent(line):
    """Get indentation level and check if line is a bullet.

    Returns (indent_level, content) if bullet, or (None, None) if not a bullet.
    Indent level 0 = top-level bullet, 1 = first nested level, etc.
    """
    # Count leading whitespace
    stripped = line.lstrip()
    if not stripped:
        return None, None

    leading_spaces = len(line) - len(stripped)

    # Check if it's a bullet line (supports -, •, *, ▪)
    for marker in BULLET_MARKERS:
        if stripped.startswith(marker):
            content = stripped[len(marker):]
            indent_level = leading_spaces // 2  # Every 2 spaces = 1 indent level
            return indent_level, content

    return None, None


def parse_bullet_list(text):
    """Convert lines starting with -, •, *, or ▪ to nested <ul><li> lists with indentation support."""
    lines = text.split('\n')
    result = []
    list_stack = []  # Stack to track nested list depths

    def close_lists_to_level(target_level):
        """Close nested lists down to target level."""
        while len(list_stack) > target_level:
            result.append('</li></ul>')
            list_stack.pop()

    def close_all_lists():
        """Close all open lists."""
        while list_stack:
            if list_stack[-1] == 'open_li':
                result.append('</li>')
            result.append('</ul>')
            list_stack.pop()

    for line in lines:
        stripped = line.strip()

        # Handle headers
        if stripped.startswith('###'):
            close_all_lists()
            header_text = stripped[3:].strip()
            if header_text:
                result.append(f'<h3>{escape_html(header_text)}</h3>')
            continue
        if stripped.startswith('##') and not stripped.startswith('###'):
            close_all_lists()
            header_text = stripped[2:].strip()
            if header_text:
                result.append(f'<h3>{escape_html(header_text)}</h3>')
            continue

        # Check for bullet
        indent_level, content = _get_bullet_indent(line)

        if indent_level is not None:
            current_depth = len(list_stack)

            if current_depth == 0:
                # Starting a new list
                result.append('<ul>')
                result.append(f'<li>{parse_formatting(escape_html(content))}')
                list_stack.append(indent_level)
            elif indent_level > list_stack[-1]:
                # Going deeper - start nested list (inside current li)
                result.append('<ul>')
                result.append(f'<li>{parse_formatting(escape_html(content))}')
                list_stack.append(indent_level)
            elif indent_level < list_stack[-1]:
                # Coming back up - close nested lists
                while list_stack and list_stack[-1] > indent_level:
                    result.append('</li></ul>')
                    list_stack.pop()
                # Close the previous li at this level and start new one
                if list_stack:
                    result.append('</li>')
                    result.append(f'<li>{parse_formatting(escape_html(content))}')
            else:
                # Same level - close previous li and start new one
                result.append('</li>')
                result.append(f'<li>{parse_formatting(escape_html(content))}')
        else:
            # Non-bullet line
            if stripped:
                close_all_lists()
                list_stack.clear()
                result.append(f'<p>{parse_formatting(escape_html(stripped))}</p>')

    # Close any remaining open lists
    while list_stack:
        result.append('</li></ul>')
        list_stack.pop()

    return '\n'.join(result)


def _indent_html(html, indent):
    if not indent:
        return html
    lines = html.split('\n')
    return '\n'.join((indent + line) if line else '' for line in lines)


def render_text_with_tables(content, indent=''):
    text = _clean_text(content)
    if not text:
        return ''

    lines = text.split('\n')
    result = []
    block = []
    table_lines = []
    in_table = False

    def flush_block():
        nonlocal block
        if block:
            block_text = '\n'.join(block).strip()
            if block_text:
                html_content = parse_bullet_list(block_text)
                if html_content.strip():
                    wrapped = f'<div class="content-block"><div class="content-header"><button class="copy-btn" onclick="copyText(this)">Copy</button></div>{html_content}</div>'
                    result.append(wrapped)
            block = []

    def flush_table():
        nonlocal table_lines, in_table
        if table_lines:
            result.append(parse_markdown_table('\n'.join(table_lines)))
            table_lines = []
        in_table = False

    for line in lines:
        stripped = line.strip()
        is_table_line = '|' in line and ('---' in line or line.count('|') >= 2)

        if is_table_line:
            flush_block()
            in_table = True
            table_lines.append(line)
        elif in_table:
            if '|' in line:
                table_lines.append(line)
            else:
                flush_table()
                block.append(line)
        else:
            block.append(line)

    flush_table()
    flush_block()

    indented_parts = [_indent_html(part.strip(), indent) for part in result if part.strip()]
    return '\n'.join(indented_parts)


def render_section_table(section_title, subsections, section_index=None):
    """Render a section as a compact 2-column table with header row."""
    if not subsections:
        return ""

    section_id = f"section-{section_index}" if section_index is not None else None
    id_attr = f' id="{section_id}"' if section_id else ''

    html = f'''<table class="section-table"{id_attr}>
  <tr class="section-header">
    <th colspan="2">{escape_html(section_title)}</th>
  </tr>'''

    for subsection in subsections:
        title = subsection.get("title", "")
        content = _clean_text(subsection.get("content", ""))
        if not content:
            continue

        # Parse content to HTML (handles both bullets and tables)
        content_html = render_text_with_tables(content)

        html += f'''
  <tr>
    <td class="label-cell">{escape_html(title)}</td>
    <td class="content-cell">{content_html}</td>
  </tr>'''

    html += '\n</table>'
    return html


def render_section_table_from_config(section_title, keys, structured_data, section_index=None):
    """Render a section table with subsections for each key."""
    subsections = []
    for key in keys:
        content = _clean_text(structured_data.get(key, ""))
        if content:
            subsections.append({"title": key, "content": content})
    if not subsections:
        return ""
    return render_section_table(section_title, subsections, section_index=section_index)


def render_subsection_card(title, content):
    """Render a single subsection as a standalone card."""
    if not content:
        return ""

    content_html = render_text_with_tables(content)

    return f'''    <div class="subsection-card">
      <div class="subsection-card-header">{escape_html(title)}</div>
      <div class="subsection-card-content">{content_html}</div>
    </div>'''


def render_section_group(section_title, subsections, section_index=None):
    """Render a section with a header and multiple standalone subsection cards."""
    if not subsections:
        return ""

    section_id = f"section-{section_index}" if section_index is not None else None
    id_attr = f' id="{section_id}"' if section_id else ''

    html = f'''<div class="section-group"{id_attr}>
  <div class="section-group-header">{escape_html(section_title)}</div>
  <div class="section-group-content">'''

    for subsection in subsections:
        title = subsection.get("title", "")
        content = _clean_text(subsection.get("content", ""))
        if content:
            html += '\n' + render_subsection_card(title, content)

    html += '''
  </div>
</div>'''
    return html


