def render_grid_section(section_title, subsections, section_index=None, columns=2):
    """Render a section with grid layout for side-by-side content blocks."""
    if not subsections:
        return ""

    section_id = f"section-{section_index}" if section_index is not None else None
    id_attr = f' id="{section_id}"' if section_id else ''

    html = f'''<div class="grid-section"{id_attr}>
  <div class="grid-section-header">{escape_html(section_title)}</div>
  <div class="grid-section-content" style="grid-template-columns: repeat({columns}, 1fr);">'''

    for i, subsection in enumerate(subsections):
        title = subsection.get("title", "")
        content = _clean_text(subsection.get("content", ""))
        span_full = subsection.get("span_full", False)
        if not content:
            continue

        content_html = render_text_with_tables(content)
        span_class = " grid-span-full" if span_full else ""

        html += f'''
    <div class="grid-block{span_class}">
      <div class="grid-block-title">{escape_html(title)}</div>
      <div class="grid-block-content">{content_html}</div>
    </div>'''

    html += '''
  </div>
</div>'''
    return html


def render_two_column_section(section_title, left_items, right_items, section_index=None, left_width="50%", right_width="50%"):
    """Render a section with two explicit columns that have equal height."""
    section_id = f"section-{section_index}" if section_index is not None else None
    id_attr = f' id="{section_id}"' if section_id else ''

    html = f'''<div class="two-col-section"{id_attr}>
  <div class="two-col-header">{escape_html(section_title)}</div>
  <div class="two-col-content" style="grid-template-columns: {left_width} {right_width};">
    <div class="two-col-left">'''

    for title, content in left_items:
        content_html = render_text_with_tables(content)
        html += f'''
      <div class="two-col-block">
        <div class="two-col-block-title">{escape_html(title)}</div>
        <div class="two-col-block-content">{content_html}</div>
      </div>'''

    html += '''
    </div>
    <div class="two-col-right">'''

    for title, content in right_items:
        content_html = render_text_with_tables(content)
        html += f'''
      <div class="two-col-block">
        <div class="two-col-block-title">{escape_html(title)}</div>
        <div class="two-col-block-content">{content_html}</div>
      </div>'''

    html += '''
    </div>
  </div>
</div>'''
    return html


