def render_card(title, main_content=None, subsections=None, main_content_html=None, section_index=None):
    section_id = f"section-{section_index}" if section_index is not None else None
    section_number = f"{section_index:02d}" if section_index is not None else None
    id_attr = f' id="{section_id}"' if section_id else ''
    number_html = f'<span class="section-number">{section_number}</span>' if section_number else ''

    html = f'''
    <div class="card"{id_attr}>
      <div class="title"><h2>{number_html}{escape_html(title)}</h2></div>
      <div class="content">'''

    if main_content_html:
        html += '\n' + _indent_html(main_content_html.strip(), '        ')
    elif main_content:
        block = render_text_with_tables(main_content, indent='        ')
        if block:
            html += '\n' + block

    if subsections:
        for section in subsections:
            title_text = escape_html(section.get("title", ""))
            content_block = render_text_with_tables(section.get("content", ""), indent='        ')
            if not content_block.strip():
                continue
            html += f'\n        <h3 class="subsection-title">{title_text}</h3>\n'
            html += content_block

    html += '\n      </div>\n    </div>'
    return html


def render_card_from_config(card_title, keys, structured_data, section_index=None):
