def _clean_text(value):
    if value is None:
        return ""
    if isinstance(value, str):
        return value.strip()
    return str(value)


def parse_merits_by_headers(text):
    """Split Investment Merits/Risks into list of (header, content) tuples by **Header** patterns.

    Only treats **text** as a header if it appears at the start of a line (not after bullet markers).
    """
    if not text:
        return []

    results = []
    lines = text.split('\n')
    current_header = None
    current_content = []

    for line in lines:
        stripped = line.strip()

        # Check if line starts with **Header** (not a bullet with bold text)
        # Header pattern: starts with ** and ends with ** (standalone bold line)
        if stripped.startswith('**') and stripped.endswith('**') and not stripped.startswith('▪') and not stripped.startswith('-'):
            # Save previous section if exists
            if current_header and current_content:
                results.append((current_header, '\n'.join(current_content)))

            # Start new section
            current_header = stripped[2:-2].strip()  # Remove ** from both ends
            current_content = []
        elif current_header is not None:
            # Add to current section content
            if stripped:  # Skip empty lines
                current_content.append(stripped)

    # Don't forget the last section
    if current_header and current_content:
        results.append((current_header, '\n'.join(current_content)))

    return results




